class Solution {
public:
    int getKth(int lo, int hi, int k) {
        vector<int> powers(hi - lo + 1);
        for (int i = lo; i <= hi; i++) {
            int power = 0;
            int x = i;
            while (x != 1) {
                if (x % 2 == 0) x /= 2;
                else x = 3 * x + 1;
                power++;
            }
            powers[i - lo] = power;
        }
        sort(powers.begin(), powers.end());
        for (int i = 0; i < powers.size(); i++) {
            if (k == 1) return lo + i;
            if (powers[i] == powers[i + k - 1]) {
                k--;
            } else {
                return lo + i + k - 1;
            }
        }
        return -1;
    }
};
